// Recibe { id, email?, name?, pdfBase64?, trackingUrl?, customMessage? }.
// id es opcional — si viene, hace lookup; si no, usa los campos directos.
const src = $input.first().json;
const body = src.body || src;
let rawId = body.id;
if (typeof rawId === 'string' && rawId.startsWith('r_')) rawId = rawId.slice(2);
const quoteId = Number.isFinite(Number(rawId)) ? Number(rawId) : null;
return [{ json: {
  quoteId,
  email: (body.email || '').trim().toLowerCase() || null,
  name: (body.name || '').trim() || null,
  pdfBase64: body.pdfBase64 || null,
  trackingUrl: (body.trackingUrl || '').trim() || null,
  customMessage: (body.customMessage || '').trim() || null,
} }];

// Resuelve email/name/trackingUrl: prioriza valores explícitos del body, fallback a la fila Postgres.
const input = $('Parse input').first().json;
const row = $input.first().json || {};
const payload = row.payload || {};
const host = $env.N8N_BASE_URL || 'https://solar-hub.co';
const toEmail = input.email || row.email;
if (!toEmail) throw new Error('Falta email del destinatario');
const toName = input.name || row.name || 'cliente';
let trackingUrl = input.trackingUrl;
if (!trackingUrl && row.id && payload.trackingToken) {
  trackingUrl = `https://solar-hub.co/?view=seguimiento&id=${row.id}&t=${encodeURIComponent(payload.trackingToken)}`;
}
const hasPdf = !!input.pdfBase64;
const customMessage = input.customMessage;

const subject = '☀ Tu cotización solar SolarHub' + (row.id ? ` #${row.id}` : '');
const htmlBody = `
<!DOCTYPE html>
<html><head><meta charset="utf-8"></head>
<body style="font-family: Arial, Helvetica, sans-serif; background:#f6f8fa; margin:0; padding:24px;">
  <div style="max-width:560px; margin:0 auto; background:#fff; border-radius:12px; overflow:hidden; box-shadow:0 2px 12px rgba(0,0,0,0.06);">
    <div style="background:#01708B; color:#fff; padding:22px 26px;">
      <div style="font-size:22px; font-weight:800;">SolarHub</div>
      <div style="font-size:13px; opacity:0.85; margin-top:2px;">Tu cotización solar está lista</div>
    </div>
    <div style="padding:24px 26px; color:#1c2733; line-height:1.6;">
      <p style="margin:0 0 12px;">Hola <strong>${escapeHtml(toName)}</strong>,</p>
      <p style="margin:0 0 12px;">Gracias por confiar en SolarHub. Adjuntamos el resumen ejecutivo de tu cotización solar.</p>
      ${customMessage ? `<p style="margin:0 0 12px; padding:12px; background:#f8f9fb; border-left:3px solid #01708B; border-radius:4px;">${escapeHtml(customMessage)}</p>` : ''}
      ${trackingUrl ? `<div style="margin:18px 0; padding:16px; background:#fff5e6; border:1px solid #FF8C0033; border-radius:8px;">
        <div style="font-size:13px; font-weight:600; color:#1c2733; margin-bottom:6px;">Sigue el estado de tu cotización</div>
        <a href="${trackingUrl}" style="display:inline-block; background:#FF8C00; color:#fff; padding:10px 22px; border-radius:6px; text-decoration:none; font-weight:600; font-size:13px;">Ver seguimiento →</a>
      </div>` : ''}
      <p style="margin:14px 0 0; font-size:13px;">Si tienes preguntas, responde este correo o escríbenos a <a href="mailto:solarhub@alebas.co" style="color:#01708B;">solarhub@alebas.co</a>.</p>
      <p style="margin:18px 0 0; font-size:13px;">¡Saludos solares!<br/><strong>El equipo de SolarHub</strong></p>
    </div>
    <div style="background:#f6f8fa; padding:14px 26px; font-size:11px; color:#7A9EAA; text-align:center;">
      SolarHub by ALEBAS Ingeniería · NIT 901.992.450-5 · Villavicencio, Meta<br/>
      Cotización válida por 30 días.
    </div>
  </div>
</body></html>`;

function escapeHtml(s) { return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

return [{ json: { toEmail, toName, subject, htmlBody, hasPdf, pdfBase64: input.pdfBase64, quoteId: row.id || input.quoteId, trackingUrl } }];

// Confirma envío y opcionalmente registra en historial de la cotización.
const built = $('Build email').first().json;
return [{ json: { ok: true, sent: true, to: built.toEmail, quoteId: built.quoteId } }];
